// 입력 데이터 파싱
const body = $input.first().json.body;
const { category, platform, urls } = body;

// 레퍼런스 콘텐츠 목록 포맷
const refList = urls.map((u, i) => 
  `${i + 1}. 제목: "${u.title}"\n   URL: ${u.url}\n   vs.Avg: ${u.vsAvg}x`
).join('\n\n');

// 플랫폼별 형식 가이드
const platformGuide = {
  youtube: '유튜브 영상 (제목 40자 이내, 썸네일 클릭유도, 첫 30초 훅 중요)',
  instagram: '인스타그램 릴스/캐러셀 (짧고 강렬한 제목, 해시태그 10개, 저장 유도)',
  'naver-blog': '네이버 블로그 포스팅 (SEO 최적화 제목, 키워드 자연스럽게 포함, 2000자 이상)',
  tistory: '티스토리 포스팅 (구글 SEO, AdSense 친화적 주제, 롱테일 키워드)'
}[platform] || '콘텐츠';

// LLM 프롬프트 구성
const prompt = `당신은 유튜브·소셜미디어 콘텐츠 전략 전문가입니다.

아래는 "${category}" 주제로 제작된 레퍼런스 콘텐츠들입니다.
vs.Avg는 채널 평균 조회수 대비 배율(높을수록 알고리즘에 더 잘 노출된 콘텐츠)입니다.

[레퍼런스 콘텐츠]
${refList}

[요청 플랫폼 형식]
${platformGuide}

위 콘텐츠들의 공통 패턴(제목 구조, 주제 각도, 감성적 훅 등)을 분석하여,
"${category}" 주제에서 비슷한 패턴을 따르되 차별화된 새 콘텐츠 3개를 제안해주세요.

반드시 아래 JSON 형식으로만 응답하세요. 다른 텍스트는 포함하지 마세요:
{
  "suggestions": [
    {
      "title": "콘텐츠 제목 (${platform === 'youtube' ? '40자 이내' : '50자 이내'})",
      "hook": "오프닝 훅 전략 (첫 15-30초에 시청자를 잡는 방법)",
      "structure": ["인트로 구성", "본론1", "본론2", "결론 + CTA"],
      "keywords": ["핵심키워드1", "키워드2", "키워드3"],
      "estimatedVsAvg": "예상 배율 범위 (예: 3.5x ~ 5.0x)",
      "reasoning": "이 제안의 근거 (어떤 패턴을 참고했는지 1-2문장)"
    }
  ]
}`;

return [{ json: { prompt, category, platform, urlCount: urls.length } }];

// Claude 또는 GPT 응답 파싱
let rawText = '';

try {
  // Claude 응답 구조
  rawText = $input.first().json.content?.[0]?.text || '';
} catch {
  // GPT 응답 구조
  rawText = $input.first().json.choices?.[0]?.message?.content || '';
}

// JSON 파싱 (마크다운 코드블록 제거)
const cleaned = rawText
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch {
  // 파싱 실패 시 기본값 반환
  parsed = {
    suggestions: [{
      title: '분석 결과 파싱 오류',
      hook: 'AI 응답 형식 오류가 발생했습니다',
      structure: ['다시 시도해주세요'],
      keywords: [],
      estimatedVsAvg: '-',
      reasoning: `원본 응답: ${rawText.slice(0, 200)}`
    }]
  };
}

return [{ json: { suggestions: parsed.suggestions || [] } }];
